import{_ as o}from"./chunks/POCKET.DAcsAyoE.js";import{_ as a}from"./chunks/chooseRx.dmJ4OLlk.js";import{_ as r,c as e,o as s,ag as n}from"./chunks/framework.DRADY2L-.js";const P=JSON.parse('{"title":"Самый бюджетный старт","description":"::: warning Важное правило Все, что дешевле комплектующих из этого списка — либо одноразовая «игрушка», либо откровенный хлам, который испортит вам впечатлен...","frontmatter":{"description":"::: warning Важное правило Все, что дешевле комплектующих из этого списка — либо одноразовая «игрушка», либо откровенный хлам, который испортит вам впечатлен...","gitAuthors":["mituritsyn"]},"headers":[],"relativePath":"ru/intro/cheapest_start.md","filePath":"ru/intro/cheapest_start.md","lastUpdated":1774733793000}'),i={name:"ru/intro/cheapest_start.md"};function l(g,t,p,c,h,d){return s(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="самыи-бюджетныи-старт" tabindex="-1">Самый бюджетный старт <a class="header-anchor" href="#самыи-бюджетныи-старт" aria-label="Permalink to &quot;Самый бюджетный старт&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Важное правило</p><p>Все, что дешевле комплектующих из этого списка — либо одноразовая «игрушка», либо откровенный хлам, который испортит вам впечатление от хобби. Вы должны понимать, что покупка всего самого дешевого несет свои риски, но мы постарались минимизировать их в этом списке.</p></div><h2 id="_1-аппаратура-управления-пульт" tabindex="-1">1. Аппаратура управления (Пульт) <a class="header-anchor" href="#_1-аппаратура-управления-пульт" aria-label="Permalink to &quot;1. Аппаратура управления (Пульт)&quot;">​</a></h2><p>Должна быть с прошивкой <strong>OpenTX</strong> или <strong>EdgeTX</strong> и протоколом <strong>ELRS</strong>. Это гарантирует, что в ней будет весь необходимый функционал, вы всегда сможете найти помощь в решении ваших хотелок или проблем, а также сможете использовать ее с любым симулятором и практически любым современным FPV-дроном.</p><p>Самый бюджетный вариант на EdgeTX - <strong>RadioMaster Pocket ELRS</strong>. Вообще почти любую аппаратуру от RadioMaster можно брать спокойно, кроме моделей <em>Zorro</em> и <em>T8 Lite</em> - там есть нюансы.</p><p class="image-container"><img src="'+o+'" height="400" alt="Аппаратура RadioMaster Pocket" title="Аппаратура RadioMaster Pocket"></p><h2 id="_2-система-радиоуправления-протокол" tabindex="-1">2. Система радиоуправления (Протокол) <a class="header-anchor" href="#_2-система-радиоуправления-протокол" aria-label="Permalink to &quot;2. Система радиоуправления (Протокол)&quot;">​</a></h2><p>Это ваш протокол связи. Выбирайте <strong>ExpressLRS (ELRS)</strong> и только его! Причем как на пульте (маркировка <em>Pocket ELRS</em>), так и встроенный приемник на самом дроне (искать в спецификациях дрона <em>ELRS 2.4G</em>).</p><p>MPM (4-in-1) и классические чипы CC2500 брать категорически нельзя — это устаревшие системы! Если у вас Whoop-дрон со встроенным FrSky или FlySky — проще его выбросить (или допаять крошечный внешний ELRS-приемник, если умеете паять).</p><p class="image-container"><img src="'+a+'" height="400" alt="Выбор протокола и приемника FPV" title="Пример вариаций квадрокоптера с приемниками"></p><h2 id="_3-видеошлем-очки" tabindex="-1">3. Видеошлем / Очки <a class="header-anchor" href="#_3-видеошлем-очки" aria-label="Permalink to &quot;3. Видеошлем / Очки&quot;">​</a></h2><p>В абсолютном большинстве случаев новичку стоит задуматься о покупке очков <strong>DJI Goggles N3</strong> - это не самое крутое в техническом плане решение, но это самая дешевая и актуальная «цифра» от DJI. Альтернатива в эту же цену - <strong>Walksnail Avatar HD Goggles L</strong>. Скайзон (<em>Skyzone Cobra</em>) лучше обходить стороной, так как он морально устарел, а по цене сопоставим с дешевой «цифрой».</p><p>Если денег совсем нет, ваш выбор - самый дешевый аналог:</p><ul><li><strong>BetaFPV VR03 / VR04</strong> (без диверсити, но компактный и дешевый);</li><li><strong>Eachine EV800D</strong> / <strong>EV800DM</strong> (Внимание: ищите только оригинальный, с надписью Eachine на лбу, клоны не брать!).</li></ul><h2 id="_4-tiny-whoop-дрон" tabindex="-1">4. Tiny Whoop (Дрон) <a class="header-anchor" href="#_4-tiny-whoop-дрон" aria-label="Permalink to &quot;4. Tiny Whoop (Дрон)&quot;">​</a></h2><p>В ультрабюджетном сегменте есть только один вариант - тинивупы. Это маленькие дроны с защитой вокруг пропеллеров, которые идеально подходят для полетов в квартире или на улице в безветренную погоду. Линейки 65-75mm ELRS-вупов от <strong>HappyModel</strong> (например, <em>Mobula 6 2024</em>) или <strong>BetaFPV</strong> (<em>Meteor65-75 / Air65</em>/ pro). <strong>Ни в коем случае не линейка Cetus.</strong></p><p>Брать вупы большего размера (85mm+) не имеет смысла: они слишком большие и тяжелые для полноценных полетов в квартире, а на улице интереснее летать на обычном дроне (без дактов/защиты вокруг пропеллеров).</p><h2 id="_5-зарядное-устроиство" tabindex="-1">5. Зарядное устройство <a class="header-anchor" href="#_5-зарядное-устроиство" aria-label="Permalink to &quot;5. Зарядное устройство&quot;">​</a></h2><ul><li><strong>VIFLY WhoopStor V3</strong> - недорогой зарядник для вуповых <code>1S</code> батареек с функцией Storage (хранения).</li><li>Если планируете летать на квадрокоптерах с 2-6 ячеечными батареями (<code>2S-6S</code>), сразу присматривайтесь к мощным зарядникам от <strong>ISDT</strong>, <strong>HOTA</strong> или <strong>ToolkitRC</strong>.</li><li>Для любителей экспериментов - портативный зарядник <em>GEPRC WooPower</em>.</li></ul><h2 id="_6-батареи" tabindex="-1">6. Батареи <a class="header-anchor" href="#_6-батареи" aria-label="Permalink to &quot;6. Батареи&quot;">​</a></h2><p>Обязательно выбирайте новые коннекторы: <strong>BT2.0</strong> или <strong>A30</strong> (это один и тот же форм-фактор). Если у дрона старый разъем <code>PH2.0</code> - лучше перепаять коннектор на дроне.</p><ul><li><strong>Топ-сегмент (дорого):</strong> Tattu, Dogcom.</li><li><strong>Бюджетно:</strong> Ovonic, BetaFPV Lava, GNB.</li></ul><hr><h2 id="ни-в-коем-случае-не-брать" tabindex="-1">НИ В КОЕМ СЛУЧАЕ НЕ БРАТЬ! <a class="header-anchor" href="#ни-в-коем-случае-не-брать" aria-label="Permalink to &quot;НИ В КОЕМ СЛУЧАЕ НЕ БРАТЬ!&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p><strong>Готовые наборы &quot;Всё-в-одном&quot; (RTF):</strong> BetaFPV Aquila, Cetus, Emax Tinyhawk BTF/RTF наборы, GEPRC TinyGO.</p><p>Особенно стоит избегать готовых комплектов (дрон + пульт + очки в одной сумке). Они доставят вам только проблемы, и их <strong>невозможно апгрейдить</strong> - придется менять практически весь комплект целиком, что в итоге выйдет значительно дороже.</p><p><em>(Чуть подробнее о том, почему не надо брать Cetus и ему подобные- читайте <a href="/ru/shop/set#почему-не-стоит-брать-цетус">в этом посте</a>.</em></p><p><strong>Вывод:</strong> Любой готовый дешевый RTF-набор будет иметь проблемы с настройкой, совместимостью и заменой запчастей. Вам просто не смогут помочь с этим в профильных чатах - лучше сразу держаться от таких коробок подальше.</p></div><blockquote><p><strong>P.S.</strong> Лучше сначала определиться с тем, в каком стиле и условиях ты хочешь летать, и <strong>подстраивать бюджет под цель</strong>, а не наоборот.<br><a href="/ru/intro/beginning">👈 Назад: С чего начать?</a></p></blockquote>',26)])])}const b=r(i,[["render",l]]);export{P as __pageData,b as default};
